# Start with the same image on both halves. Edit this independently when you
# want the right OLED to differ from the left one.
RIGHT_OLED_FRAMES = LEFT_OLED_FRAMES


def pack_frame(frame):
    packed = [0] * (OLED_WIDTH * (OLED_HEIGHT // 8))
    for y, row in enumerate(frame):
        if len(row) != OLED_WIDTH:
            raise ValueError(f"row {y} has {len(row)} cells; expected {OLED_WIDTH}")
        for x, cell in enumerate(row):
            if cell not in (0, 1):
                raise ValueError(f"frame cell ({x}, {y}) must be 0 or 1")
            if cell:
                packed[(y // 8) * OLED_WIDTH + x] |= 1 << (y % 8)
    return packed


def render_frame_array(name, frames):
    lines = [f"static const uint8_t PROGMEM {name}[{len(frames)}][OLED_MATRIX_SIZE] = {{"]
    for frame in frames:
        lines.append("    {")
        for offset in range(0, len(frame), 16):
            chunk = ", ".join(f"0x{byte:02x}" for byte in frame[offset:offset + 16])
            lines.append(f"        {chunk},")
        lines.append("    },")
    lines.append("};")
    return lines


def render_header(left_frames, right_frames):
    lines = [
        "// Generated by generate_oled_frames.py. Do not edit this file directly.",
        "#pragma once",
        "",
        f"#define LEFT_OLED_FRAME_COUNT {len(left_frames)}",
        f"#define RIGHT_OLED_FRAME_COUNT {len(right_frames)}",
        "",
    ]
    lines.extend(render_frame_array("left_oled_frames", left_frames))
    lines.append("")
    lines.extend(render_frame_array("right_oled_frames", right_frames))
    return "\n".join(lines) + "\n"


def main():
    if not LEFT_OLED_FRAMES:
        raise ValueError("at least one left OLED frame is required")
    if not RIGHT_OLED_FRAMES:
        raise ValueError("at least one right OLED frame is required")

    packed_left_frames = []
    for index, frame in enumerate(LEFT_OLED_FRAMES):
        if len(frame) != OLED_HEIGHT:
            raise ValueError(f"left frame {index} has {len(frame)} rows; expected {OLED_HEIGHT}")
        packed_left_frames.append(pack_frame(frame))

    packed_right_frames = []
    for index, frame in enumerate(RIGHT_OLED_FRAMES):
        if len(frame) != OLED_HEIGHT:
            raise ValueError(f"right frame {index} has {len(frame)} rows; expected {OLED_HEIGHT}")
        packed_right_frames.append(pack_frame(frame))

    output = Path(__file__).with_name("oled_frames_generated.h")
    output.write_text(render_header(packed_left_frames, packed_right_frames))


if __name__ == "__main__":
    main()
